import{_ as a,o as i,c as l,ae as t}from"./chunks/framework.DeBUZsJm.js";const h=JSON.parse('{"title":"Packaging & Release","description":"","frontmatter":{},"headers":[],"relativePath":"packaging-and-release.md","filePath":"packaging-and-release.md","lastUpdated":1775513914000}'),r={name:"packaging-and-release.md"};function n(o,e,s,p,c,d){return i(),l("div",null,[...e[0]||(e[0]=[t('<h1 id="packaging-release" tabindex="-1">Packaging &amp; Release <a class="header-anchor" href="#packaging-release" aria-label="Permalink to &quot;Packaging &amp; Release&quot;">​</a></h1><h2 id="output-format" tabindex="-1">Output format <a class="header-anchor" href="#output-format" aria-label="Permalink to &quot;Output format&quot;">​</a></h2><p>Astrogram plugins are native shared libraries distributed with the <code>.tgd</code> suffix.</p><p>Typical flow:</p><ol><li>build your plugin library</li><li>rename or emit it as <code>.tgd</code></li><li>place it into the plugins directory</li><li>let Astrogram rescan it automatically</li></ol><h2 id="preview-metadata" tabindex="-1">Preview metadata <a class="header-anchor" href="#preview-metadata" aria-label="Permalink to &quot;Preview metadata&quot;">​</a></h2><p>Use preview metadata so the client can show install information before plugin code runs:</p><ul><li>name</li><li>version</li><li>author</li><li>description</li><li>website</li><li>optional icon reference</li></ul><p>This is what powers the install/update preview in chat-driven plugin installation flows.</p><h2 id="versioning-recommendations" tabindex="-1">Versioning recommendations <a class="header-anchor" href="#versioning-recommendations" aria-label="Permalink to &quot;Versioning recommendations&quot;">​</a></h2><ul><li>keep a stable plugin ID forever</li><li>bump versions on every shipped binary</li><li>avoid in-place replacement of unrelated plugin IDs</li><li>keep changelog notes for users when behavior changes significantly</li></ul><h2 id="separate-plugin-ci" tabindex="-1">Separate plugin CI <a class="header-anchor" href="#separate-plugin-ci" aria-label="Permalink to &quot;Separate plugin CI&quot;">​</a></h2><p>Astrogram is moving toward selective plugin runners so a medium plugin change does not rebuild the whole catalog every time.</p><p>Recommended pipeline split:</p><ul><li>plugin-specific build workflow</li><li>catalog sanity workflow</li><li>client workflow kept separate from plugin packaging</li></ul><h2 id="release-checklist" tabindex="-1">Release checklist <a class="header-anchor" href="#release-checklist" aria-label="Permalink to &quot;Release checklist&quot;">​</a></h2><ul><li>build passes on the target platform</li><li>preview metadata matches the shipped binary</li><li>settings page works without crashes</li><li>install / update / disable / re-enable flow works</li><li><code>plugins.log</code> stays clean during normal load</li></ul>',17)])])}const g=a(r,[["render",n]]);export{h as __pageData,g as default};
